package tests;import base.BaseTestPlaywright;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP01PanelCocineroPlaywrightTest        extends BaseTestPlaywright {    @Test    void panelCocineroMuestraPedidosPendientes() {        page.navigate(                "https://ernest.xo.je/index.php?route=auth/login"        );        page.locator(                "input[name='username']"        ).fill("cocinero");        page.locator(                "input[name='password']"        ).fill("123");        page.locator(                "button[type='submit']"        ).click();        page.waitForTimeout(2000);        assertTrue(                page.content()                        .contains("Panel Cocinero")        );        assertTrue(                page.content()                        .contains("Pedidos Pendientes")        );    }}